    19→    /// <summary>
    20→    /// A LookupResult summarizes the result of a name lookup within a scope It also allows
    21→    /// combining name lookups from different scopes in an easy way.
    22→    /// 
    23→    /// A LookupResult can be ONE OF:
    24→    ///    empty - nothing found.
    25→    ///    a viable result - this kind of result prevents lookup into further scopes of lower priority.
    26→    ///                      Viable results should be without error; ambiguity is handled in the caller.
    27→    ///                      (Note that handling multiple "viable" results is not the same as in the VB compiler)
    28→    ///    a non-accessible result - this kind of result means that search continues into further scopes of lower priority for
    29→    ///                      a viable result. An error is attached with the inaccessibility errors. Non-accessible results take priority over
    30→    ///                      non-viable results.
    31→    ///    a non-viable result - a result that means that the search continues into further scopes of lower priority for
    32→    ///                          a viable or non-accessible result. An error is attached with the error that indicates
    33→    ///                          why the result is non-viable.  A typical reason would be that it is the wrong kind of symbol.
    34→    /// 
    35→    /// Note that the class is poolable so its instances can be obtained from a pool via GetInstance.
    36→    /// Also it is a good idea to call Free on instances after they no longer needed.
    37→    /// 
    38→    /// The typical pattern is "caller allocates / caller frees" -
    39→    ///    
    40→    ///    var result = LookupResult.GetInstance();
    41→    ///  
    42→    ///    scope.Lookup(result, "goo");
    43→    ///    ... use result ...
    44→    ///         
    45→    ///    result.Clear();
    46→    ///    anotherScope.Lookup(result, "moo");
    47→    ///    ... use result ...
    48→    /// 
    49→    ///    result.Free();   //result and its content is invalid after this
    50→    ///    
    51→    /// 
    52→    /// 
    53→    /// </summary>
    54→    /// <remarks>
    55→    /// Currently LookupResult is intended only for name lookup, not for overload resolution. It is
    56→    /// not clear if overload resolution will work with the structure as is, require enhancements,
    57→    /// or be best served by an alternate mechanism.
    58→    /// 
    59→    /// We might want to extend this to a more general priority scheme.
    60→    /// 
    61→    /// </remarks>
    62→    internal sealed class LookupResult
    63→    {
    64→        // the kind of result.
    65→        private LookupResultKind _kind;
    66→
    67→        // If there is more than one symbol, they are stored in this list.
    68→        private readonly ArrayBuilder<Symbol> _symbolList;
    69→
    70→        // the error of the result, if it is NonViable or Inaccessible
    71→        private DiagnosticInfo _error;
    72→
    73→        private readonly ObjectPool<LookupResult> _pool;
    74→
    75→        private LookupResult(ObjectPool<LookupResult> pool)
    76→        {
    77→            _pool = pool;
    78→            _kind = LookupResultKind.Empty;
    79→            _symbolList = new ArrayBuilder<Symbol>();
    80→            _error = null;
    81→        }
    82→
    83→        internal bool IsClear
    84→        {
    85→            get
    86→            {
    87→                return _kind == LookupResultKind.Empty && _error == null && _symbolList.Count == 0;
    88→            }
    89→        }
    90→
    91→        internal void Clear()
    92→        {
    93→            _kind = LookupResultKind.Empty;
    94→            _symbolList.Clear();
    95→            _error = null;
    96→        }
    97→
    98→        internal LookupResultKind Kind
    99→        {
   100→            get
   101→            {
   102→                return _kind;
   103→            }
   104→        }
   105→
   106→        /// <summary>
   107→        /// Return the single symbol if there is exactly one, otherwise null.
   108→        /// </summary>
   109→        internal Symbol SingleSymbolOrDefault
   110→        {
   111→            get
   112→            {
   113→                return (_symbolList.Count == 1) ? _symbolList[0] : null;
   114→            }
   115→        }
   116→
   117→        internal ArrayBuilder<Symbol> Symbols
   118→        {
   119→            get
   120→            {
   121→                return _symbolList;
   122→            }
   123→        }
   124→
   125→        internal DiagnosticInfo Error
   126→        {
   127→            get
   128→            {
   129→                return _error;
   130→            }
   131→        }
   132→
   133→        /// <summary>
   134→        /// Is the result viable with one or more symbols?
   135→        /// </summary>
   136→        internal bool IsMultiViable
   137→        {
   138→            get
   139→            {
   140→                return Kind == LookupResultKind.Viable;
   141→            }
   142→        }
   143→
   144→        /// <summary>
   145→        /// NOTE: Even there is a single viable symbol, it may be an error type symbol.
   146→        /// </summary>
   147→        internal bool IsSingleViable
   148→        {
   149→            get
   150→            {
   151→                return Kind == LookupResultKind.Viable && _symbolList.Count == 1;
   152→            }
   153→        }
   154→
   155→        internal static SingleLookupResult Good(Symbol symbol)
   156→        {
   157→            return new SingleLookupResult(LookupResultKind.Viable, symbol, null);
   158→        }
   159→
   160→        internal static SingleLookupResult WrongArity(Symbol symbol, DiagnosticInfo error)
   161→        {
   162→            return new SingleLookupResult(LookupResultKind.WrongArity, symbol, error);
   163→        }
   164→
   165→        internal static SingleLookupResult Empty()
   166→        {
   167→            return new SingleLookupResult(LookupResultKind.Empty, null, null);
   168→        }
   169→
   170→        internal static SingleLookupResult NotReferencable(Symbol symbol, DiagnosticInfo error)
   171→        {
   172→            return new SingleLookupResult(LookupResultKind.NotReferencable, symbol, error);
   173→        }
   174→
   175→        internal static SingleLookupResult StaticInstanceMismatch(Symbol symbol, DiagnosticInfo error)
   176→        {
   177→            return new SingleLookupResult(LookupResultKind.StaticInstanceMismatch, symbol, error);
   178→        }
   179→
   180→        internal static SingleLookupResult Inaccessible(Symbol symbol, DiagnosticInfo error)
   181→        {
   182→            return new SingleLookupResult(LookupResultKind.Inaccessible, symbol, error);
   183→        }
   184→
   185→        internal static SingleLookupResult NotInvocable(Symbol unwrappedSymbol, Symbol symbol, bool diagnose)
   186→        {
   187→            var diagInfo = diagnose ? new CSDiagnosticInfo(ErrorCode.ERR_NonInvocableMemberCalled, unwrappedSymbol) : null;
   188→            return new SingleLookupResult(LookupResultKind.NotInvocable, symbol, diagInfo);
   189→        }
   190→
   191→        internal static SingleLookupResult NotLabel(Symbol symbol, DiagnosticInfo error)
   192→        {
   193→            return new SingleLookupResult(LookupResultKind.NotLabel, symbol, error);
   194→        }
   195→
   196→        internal static SingleLookupResult NotTypeOrNamespace(Symbol symbol, DiagnosticInfo error)
   197→        {
   198→            return new SingleLookupResult(LookupResultKind.NotATypeOrNamespace, symbol, error);
   199→        }
   200→
   201→        internal static SingleLookupResult NotTypeOrNamespace(Symbol unwrappedSymbol, Symbol symbol, bool diagnose)
   202→        {
   203→            // TODO: determine correct diagnosis 
   204→            var diagInfo = diagnose ? new CSDiagnosticInfo(ErrorCode.ERR_BadSKknown, unwrappedSymbol.Name, unwrappedSymbol.GetKindText(), MessageID.IDS_SK_TYPE.Localize()) : null;
   205→            return new SingleLookupResult(LookupResultKind.NotATypeOrNamespace, symbol, diagInfo);
   206→        }
   207→
   208→        internal static SingleLookupResult NotAnAttributeType(Symbol symbol, DiagnosticInfo error)
   209→        {
   210→            return new SingleLookupResult(LookupResultKind.NotAnAttributeType, symbol, error);
   211→        }
   212→
   213→        /// <summary>
   214→        /// Set current result according to another.
   215→        /// </summary>
   216→        internal void SetFrom(SingleLookupResult other)
   217→        {
   218→            _kind = other.Kind;
   219→            _symbolList.Clear();
   220→            _symbolList.Add(other.Symbol);
   221→            _error = other.Error;
   222→        }
   223→
   224→        /// <summary>
   225→        /// Set current result according to another.
   226→        /// </summary>
   227→        internal void SetFrom(LookupResult other)
   228→        {
   229→            _kind = other._kind;
   230→            _symbolList.Clear();
   231→            _symbolList.AddRange(other._symbolList);
   232→            _error = other._error;
   233→        }
   234→
   235→        internal void SetFrom(DiagnosticInfo error)
   236→        {
   237→            this.Clear();
   238→            _error = error;
   239→        }
   240→
   241→        // Merge another result with this one, with the current result being prioritized
   242→        // over the other if they are of equal "goodness". Mutates the current result.
   243→        internal void MergePrioritized(LookupResult other)
   244→        {
   245→            if (other.Kind > Kind)
   246→            {
   247→                SetFrom(other);
   248→            }
   249→        }
   250→
   251→        /// <summary>
   252→        /// Merge another result with this one, with the symbols combined if both
   253→        /// this and other are viable. Otherwise the highest priority result wins (this if equal 
   254→        /// priority and non-viable.)
   255→        /// </summary>
   256→        internal void MergeEqual(LookupResult other)
   257→        {
   258→            if (Kind > other.Kind)
   259→            {
   260→                return;
   261→            }
   262→            else if (other.Kind > Kind)
   263→            {
   264→                this.SetFrom(other);
   265→            }
   266→            else if (Kind != LookupResultKind.Viable)
   267→            {
   268→                // this makes the operator not symmetrical, but so far we do not care.
   269→                // it is really a matter of which error gets reported.
   270→                return;
   271→            }
   272→            else
   273→            {
   274→                // Merging two viable results together. We will always end up with at least two symbols.
   275→                _symbolList.AddRange(other._symbolList);
   276→            }
   277→        }
   278→
   279→        internal void MergeEqual(SingleLookupResult result)
   280→        {
   281→            if (Kind > result.Kind)
   282→            {
   283→                // existing result is better
   284→            }
   285→            else if (result.Kind > Kind)
   286→            {
   287→                this.SetFrom(result);
   288→            }
   289→            else if ((object)result.Symbol != null)
   290→            {
   291→                // Same goodness. Include all symbols
   292→                _symbolList.Add(result.Symbol);
   293→            }
   294→        }
   295→
   296→        // global pool
   297→        //TODO: consider if global pool is ok.
   298→        private static readonly ObjectPool<LookupResult> s_poolInstance = CreatePool();
   299→
   300→        // if someone needs to create a pool
   301→        internal static ObjectPool<LookupResult> CreatePool()
   302→        {
   303→            ObjectPool<LookupResult> pool = null;
   304→            pool = new ObjectPool<LookupResult>(() => new LookupResult(pool), 128); // we rarely need more than 10
   305→            return pool;
   306→        }
   307→
   308→        internal static LookupResult GetInstance()
   309→        {
   310→            var instance = s_poolInstance.Allocate();
   311→            Debug.Assert(instance.IsClear);
   312→            return instance;
   313→        }
   314→
   315→        internal void Free()
   316→        {
   317→            this.Clear();
   318→            if (_pool != null)
   319→            {
   320→                _pool.Free(this);
   321→            }
   322→        }
   323→    }
   324→}
