    61→        private Binder LookupSymbolsWithFallback(LookupResult result, string name, int arity, ref CompoundUseSiteInfo<AssemblySymbol> useSiteInfo, ConsList<TypeSymbol> basesBeingResolved = null, LookupOptions options = LookupOptions.Default)
    62→        {
    63→            Debug.Assert(options.AreValid());
    64→
    65→            // don't create diagnosis instances unless lookup fails
    66→            var binder = this.LookupSymbolsInternal(result, name, arity, basesBeingResolved, options, diagnose: false, useSiteInfo: ref useSiteInfo);
    67→            Debug.Assert((binder != null) || result.IsClear);
    68→
    69→            if (result.Kind != LookupResultKind.Viable && result.Kind != LookupResultKind.Empty)
    70→            {
    71→                result.Clear();
