    73→                var otherBinder = this.LookupSymbolsInternal(result, name, arity, basesBeingResolved, options, diagnose: true, useSiteInfo: ref useSiteInfo);
    74→                Debug.Assert(binder == otherBinder);
    75→            }
    76→
    77→            Debug.Assert(result.IsMultiViable || result.IsClear || result.Error != null);
